import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void sortBySecondColumn() {
        // col-1 values: 2,5,4 => order: [3,2],[2,4],[1,5]
        int[][] input = {{3,2},{1,5},{2,4}};
        int[][] result = new Solution().sortByColumn(input, 1);
        assertEquals(3, result.length);
        assertArrayEquals(new int[]{3,2}, result[0]);
        assertArrayEquals(new int[]{2,4}, result[1]);
        assertArrayEquals(new int[]{1,5}, result[2]);
    }

    @Test
    void sortByFirstColumn() {
        // col-0 values: 3,1,2 => order: [1,5],[2,4],[3,2]
        int[][] input = {{3,2},{1,5},{2,4}};
        int[][] result = new Solution().sortByColumn(input, 0);
        assertEquals(3, result.length);
        assertArrayEquals(new int[]{1,5}, result[0]);
        assertArrayEquals(new int[]{2,4}, result[1]);
        assertArrayEquals(new int[]{3,2}, result[2]);
    }

    @Test
    void threeColumnMatrix() {
        // col-2 values: 30,3,6 => order: [1,2,3],[4,5,6],[10,20,30]
        int[][] input = {{10,20,30},{1,2,3},{4,5,6}};
        int[][] result = new Solution().sortByColumn(input, 2);
        assertEquals(3, result.length);
        assertArrayEquals(new int[]{1,2,3},    result[0]);
        assertArrayEquals(new int[]{4,5,6},    result[1]);
        assertArrayEquals(new int[]{10,20,30}, result[2]);
    }

    @Test
    void alreadySorted() {
        // already sorted ascending by col-0; result should be identical in value
        int[][] input = {{1,9},{2,8},{3,7}};
        int[][] result = new Solution().sortByColumn(input, 0);
        assertEquals(3, result.length);
        assertArrayEquals(new int[]{1,9}, result[0]);
        assertArrayEquals(new int[]{2,8}, result[1]);
        assertArrayEquals(new int[]{3,7}, result[2]);
    }

    @Test
    void singleRow() {
        int[][] input = {{5,3,8}};
        int[][] result = new Solution().sortByColumn(input, 2);
        assertEquals(1, result.length);
        assertArrayEquals(new int[]{5,3,8}, result[0]);
    }

    @Test
    void doesNotMutateInput() {
        // the returned array must be a different object from the input
        int[][] input = {{3,2},{1,5},{2,4}};
        int[][] result = new Solution().sortByColumn(input, 1);
        assertNotSame(input, result);
        // original must be untouched
        assertArrayEquals(new int[]{3,2}, input[0]);
        assertArrayEquals(new int[]{1,5}, input[1]);
        assertArrayEquals(new int[]{2,4}, input[2]);
    }

    @Test
    void empty() {
        int[][] result = new Solution().sortByColumn(new int[][]{}, 0);
        assertEquals(0, result.length);
    }
}
